import ccxt.async_support as ccxt  # noqa: F402
from ccxt.test.exchange.base import test_shared_methods  # noqa E402

async def test_fetch_history_base():
    exchange = ccxt.Exchange({
        'id': 'sampleexchange',
        'fetchHistoryCacheSize': 2,
    })
    assert test_shared_methods.exchange_prop(exchange, 'fetchHistoryCacheSize') == 2, 'fetchHistoryCacheSize should be 2'
    true_assertion = exchange.parse_number(None) is None
    try:
        await exchange.fetch2('sample1')
    except Exception as error:
        assert true_assertion  # just skip
    assert len((exchange.get_fetch_cache())) == 1, 'fetchHistoryCache should be an array with 1 element'
    try:
        await exchange.fetch2('sample2')
    except Exception as error:
        assert true_assertion  # just skip
    assert len((exchange.get_fetch_cache())) == 2, 'fetchHistoryCache should be an array with 2 elements'
    try:
        await exchange.fetch2('sample3')
    except Exception as error:
        assert true_assertion  # just skip
    assert len((exchange.get_fetch_cache())) == 2, 'fetchHistoryCache should be an array with 2 elements'
    assert 1 + 1 < 3, 'sample assertion'


async def test_fetch_history_derived():
    exchange = ccxt.coinbase({
        'id': 'sampleexchange',
        'fetchHistoryCacheSize': 2,
    })
    # try 3 times
    # first
    await exchange.fetch_time()  # https://api.coinbase.com/api/v3/brokerage/time
    assert len((exchange.get_fetch_cache())) == 1, 'fetchHistoryCache should be an array with 1 element'
    # second
    await exchange.fetch_order_book('BTC/USD')  # https://api.coinbase.com/api/v3/brokerage/market/product_book?product_id=BTC-USD
    assert len((exchange.get_fetch_cache())) == 2, 'fetchHistoryCache should be an array with 2 elements'
    # third
    await exchange.fetch_trades('BTC/USD')  # https://api.coinbase.com/api/v3/brokerage/market/products/BTC-USD/ticker
    assert len((exchange.get_fetch_cache())) == 2, 'fetchHistoryCache should be an array with 2 elements'
    final_cache = exchange.get_fetch_cache()
    assert str(final_cache[0]['request']['url']) == 'https://api.coinbase.com/api/v3/brokerage/market/product_book?product_id=BTC-USD', 'The first element in fetchHistoryCache is : ' + final_cache[0]['request']['url']
    assert str(final_cache[1]['request']['url']) == 'https://api.coinbase.com/api/v3/brokerage/market/products/BTC-USD/ticker', 'The second element in fetchHistoryCache is : ' + final_cache[1]['request']['url']
    assert 1 + 1 < 3, 'sample assertion'


async def test_fetch_history():
    await test_fetch_history_base()
    await test_fetch_history_derived()
